fn solve(n: i64) -> bool {
    let mut temp = n;
    let mut sum = 0;
    let mut product = 1;
    while temp != 0 {
        let digit = temp % 10;
        sum += digit;
        product *= digit;
        temp /= 10;
    }
    let total = sum + product;
    n % total == 0
}
```

